import os
import uuid
import hashlib
import magic
from flask import Flask, request, jsonify, send_from_directory
from werkzeug.utils import secure_filename
from PIL import Image

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = os.path.join(os.path.abspath(os.path.dirname(__file__)), 'uploads', 'profile_pictures')
ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif', 'webp'}
ALLOWED_MIME_TYPES = {'image/png', 'image/jpeg', 'image/gif', 'image/webp'}
MAX_CONTENT_LENGTH = 5 * 1024 * 1024  # 5 MB max file size
MAX_IMAGE_DIMENSION = 2048  # Max width/height in pixels
THUMBNAIL_SIZE = (256, 256)

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_CONTENT_LENGTH

# Ensure upload directory exists
os.makedirs(UPLOAD_FOLDER, exist_ok=True)


def allowed_extension(filename):
    """Check if the file has an allowed extension."""
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


def validate_mime_type(file_stream):
    """Validate the MIME type of the file by reading its magic bytes."""
    file_stream.seek(0)
    mime = magic.from_buffer(file_stream.read(2048), mime=True)
    file_stream.seek(0)
    return mime in ALLOWED_MIME_TYPES


def validate_image(file_stream):
    """Validate that the file is a legitimate image and check dimensions."""
    try:
        file_stream.seek(0)
        img = Image.open(file_stream)
        img.verify()  # Verify it's a valid image
        file_stream.seek(0)

        # Re-open after verify (verify closes the file)
        img = Image.open(file_stream)
        width, height = img.size
        file_stream.seek(0)

        if width > MAX_IMAGE_DIMENSION or height > MAX_IMAGE_DIMENSION:
            return False, f"Image dimensions exceed maximum of {MAX_IMAGE_DIMENSION}x{MAX_IMAGE_DIMENSION} pixels."

        if width < 1 or height < 1:
            return False, "Image dimensions are invalid."

        return True, None
    except Exception:
        return False, "File is not a valid image."


def generate_safe_filename(original_filename):
    """Generate a unique, safe filename preserving the original extension."""
    ext = original_filename.rsplit('.', 1)[1].lower() if '.' in original_filename else 'png'
    if ext not in ALLOWED_EXTENSIONS:
        ext = 'png'
    unique_id = uuid.uuid4().hex
    return f"{unique_id}.{ext}"


def process_and_save_image(file_stream, save_path):
    """Re-encode the image to strip metadata and potential exploits, then save."""
    file_stream.seek(0)
    img = Image.open(file_stream)

    # Convert to RGB if necessary (handles RGBA, palette, etc.)
    if img.mode in ('RGBA', 'LA', 'P'):
        # Preserve transparency for PNG/GIF/WebP
        if save_path.lower().endswith(('.png', '.gif', '.webp')):
            img = img.convert('RGBA')
        else:
            background = Image.new('RGB', img.size, (255, 255, 255))
            if img.mode == 'P':
                img = img.convert('RGBA')
            background.paste(img, mask=img.split()[-1] if len(img.split()) == 4 else None)
            img = background
    elif img.mode != 'RGB':
        img = img.convert('RGB')

    # Resize if too large
    if img.width > MAX_IMAGE_DIMENSION or img.height > MAX_IMAGE_DIMENSION:
        img.thumbnail((MAX_IMAGE_DIMENSION, MAX_IMAGE_DIMENSION), Image.LANCZOS)

    # Save re-encoded image (strips EXIF and other metadata)
    img.save(save_path, quality=85)

    # Also create a thumbnail
    thumbnail_path = save_path.rsplit('.', 1)[0] + '_thumb.' + save_path.rsplit('.', 1)[1]
    thumb = img.copy()
    thumb.thumbnail(THUMBNAIL_SIZE, Image.LANCZOS)
    thumb.save(thumbnail_path, quality=85)

    return thumbnail_path


def compute_file_hash(file_stream):
    """Compute SHA-256 hash of the file for deduplication or integrity checks."""
    file_stream.seek(0)
    sha256 = hashlib.sha256()
    while True:
        chunk = file_stream.read(8192)
        if not chunk:
            break
        sha256.update(chunk)
    file_stream.seek(0)
    return sha256.hexdigest()


@app.route('/api/profile/upload', methods=['POST'])
def upload_profile_picture():
    """
    Upload a profile picture.
    Expects a multipart/form-data request with a 'file' field.
    """
    # Check if file is present in request
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided.'}), 400

    file = request.files['file']

    if file.filename is None or file.filename.strip() == '':
        return jsonify({'error': 'No file selected.'}), 400

    # Secure the original filename
    original_filename = secure_filename(file.filename)

    if not original_filename:
        return jsonify({'error': 'Invalid filename.'}), 400

    # Check file extension
    if not allowed_extension(original_filename):
        return jsonify({
            'error': f'File type not allowed. Allowed types: {", ".join(ALLOWED_EXTENSIONS)}'
        }), 400

    # Validate MIME type using magic bytes
    if not validate_mime_type(file.stream):
        return jsonify({'error': 'File MIME type is not allowed or does not match a valid image type.'}), 400

    # Validate image integrity and dimensions
    is_valid, error_msg = validate_image(file.stream)
    if not is_valid:
        return jsonify({'error': error_msg}), 400

    # Compute file hash
    file_hash = compute_file_hash(file.stream)

    # Generate a safe, unique filename
    safe_filename = generate_safe_filename(original_filename)
    save_path = os.path.join(app.config['UPLOAD_FOLDER'], safe_filename)

    # Ensure the save path is within the upload folder (path traversal prevention)
    real_upload_folder = os.path.realpath(app.config['UPLOAD_FOLDER'])
    real_save_path = os.path.realpath(save_path)
    if not real_save_path.startswith(real_upload_folder + os.sep):
        return jsonify({'error': 'Invalid file path.'}), 400

    try:
        # Process and save the image (re-encodes to strip metadata/exploits)
        thumbnail_path = process_and_save_image(file.stream, save_path)
    except Exception as e:
        app.logger.error(f"Error processing image: {e}")
        return jsonify({'error': 'Failed to process image.'}), 500

    thumbnail_filename = os.path.basename(thumbnail_path)

    return jsonify({
        'message': 'Profile picture uploaded successfully.',
        'filename': safe_filename,
        'thumbnail': thumbnail_filename,
        'file_hash': file_hash,
        'url': f'/api/profile/picture/{safe_filename}',
        'thumbnail_url': f'/api/profile/picture/{thumbnail_filename}'
    }), 201


@app.route('/api/profile/picture/<filename>', methods=['GET'])
def get_profile_picture(filename):
    """Serve a profile picture by filename."""
    # Secure the filename to prevent path traversal
    safe_name = secure_filename(filename)
    if not safe_name or safe_name != filename:
        return jsonify({'error': 'Invalid filename.'}), 400

    # Verify the file path is within the upload directory
    file_path = os.path.join(app.config['UPLOAD_FOLDER'], safe_name)
    real_upload_folder = os.path.realpath(app.config['UPLOAD_FOLDER'])
    real_file_path = os.path.realpath(file_path)

    if not real_file_path.startswith(real_upload_folder + os.sep):
        return jsonify({'error': 'Invalid file path.'}), 400

    if not os.path.isfile(real_file_path):
        return jsonify({'error': 'File not found.'}), 404

    return send_from_directory(
        app.config['UPLOAD_FOLDER'],
        safe_name,
        max_age=3600
    )


@app.errorhandler(413)
def request_entity_too_large(error):
    """Handle file too large errors."""
    return jsonify({
        'error': f'File too large. Maximum size is {MAX_CONTENT_LENGTH // (1024 * 1024)} MB.'
    }), 413


@app.errorhandler(400)
def bad_request(error):
    return jsonify({'error': 'Bad request.'}), 400


@app.errorhandler(500)
def internal_error(error):
    return jsonify({'error': 'Internal server error.'}), 500


if __name__ == '__main__':
    # In production, use a proper WSGI server (gunicorn, uwsgi, etc.)
    # and set debug=False
    app.run(debug=False, host='127.0.0.1', port=5000)